'use server';

import { updateTag, refresh } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const body = formData.get('body') as string;

  if (!title || !body) {
    throw new Error('Title and body are required');
  }

  addPost(title, body);

  // updateTag invalidates the server data cache for the 'posts' tag and
  // enables read-your-own-writes semantics — the next server render that
  // encounters a fetch tagged with 'posts' will wait for fresh data
  // instead of serving stale cached content.
  updateTag('posts');

  // Clear the client-side router cache, so the redirect that follows
  // doesn't render a client-cached stale version of the page.
  refresh();

  // Redirect back to the page.  The combination of updateTag + refresh
  // guarantees the browser requests a fresh server render and that render
  // re-fetches the posts list synchronously.
  redirect('/');
}

